function validateValue(value, expectedType) {
  if (value === null || value === undefined) {
    return value;
  }

  switch (expectedType) {
    case 'string':
      if (typeof value !== 'string') {
        throw new Error(`Expected string, got ${typeof value}`);
      }
      if (value.length > 1000) {
        throw new Error('String value too long');
      }
      return value;
    
    case 'number':
      const num = Number(value);
      if (isNaN(num)) {
        throw new Error(`Invalid number: ${value}`);
      }
      return num;
    
    case 'boolean':
      if (typeof value === 'boolean') return value;
      if (value === 'true') return true;
      if (value === 'false') return false;
      throw new Error(`Invalid boolean: ${value}`);
    
    case 'date':
      const date = new Date(value);
      if (isNaN(date.getTime())) {
        throw new Error(`Invalid date: ${value}`);
      }
      return date;
    
    case 'objectid':
      if (ObjectId.isValid(value)) {
        return new ObjectId(value);
      }
      throw new Error(`Invalid ObjectId: ${value}`);
    
    default:
      throw new Error(`Unknown type: ${expectedType}`);
  }
}

function validateRegex(pattern, options) {
  if (typeof pattern !== 'string') {
    throw new Error('Regex pattern must be a string');
  }
  
  if (pattern.length > 500) {
    throw new Error('Regex pattern too long');
  }
  
  const dangerousPatterns = [
    /\(\?.*\)/,
    /\{\d{3,}\}/,
    /\*\*/,
    /\+\+/
  ];
  
  for (const dangerous of dangerousPatterns) {
    if (dangerous.test(pattern)) {
      throw new Error('Potentially dangerous regex pattern detected');
    }
  }
  
  if (options && typeof options !== 'string') {
    throw new Error('Regex options must be a string');
  }
  
  if (options && !/^[imxs]*$/.test(options)) {
    throw new Error('Invalid regex options');
  }
  
  try {
    new RegExp(pattern, options);
  } catch (e) {
    throw new Error(`Invalid regex: ${e.message}`);
  }
  
  return true;
}

function validateOperatorValue(operator, value, fieldType) {
  switch (operator) {
    case '$eq':
    case '$ne':
    case '$gt':
    case '$gte':
    case '$lt':
    case '$lte':
      return validateValue(value, fieldType);
    
    case '$in':
    case '$nin':
      if (!Array.isArray(value)) {
        throw new Error(`${operator} requires an array`);
      }
      if (value.length > 100) {
        throw new Error(`${operator} array too large`);
      }
      return value.map(v => validateValue(v, fieldType));
    
    case '$exists':
      if (typeof value !== 'boolean') {
        throw new Error('$exists requires a boolean value');
      }
      return value;
    
    case '$type':
      const validTypes = ['string', 'number', 'object', 'array', 'bool', 'date', 'null', 'objectId'];
      if (!validTypes.includes(value)) {
        throw new Error(`Invalid $type value: ${value}`);
      }
      return value;
    
    case '$regex':
      if (typeof value === 'string') {
        validateRegex(value);
        return value;
      } else if (value instanceof RegExp) {
        validateRegex(value.source, value.flags);
        return value;
      }
      throw new Error('$regex requires a string or RegExp');
    
    case '$options':
      if (typeof value !== 'string') {
        throw new Error('$options requires a string');
      }
      return value;
    
    default:
      throw new Error(`Unsupported operator: ${operator}`);
  }
}

function validateAndBuildFilter(filterObj) {
  if (!filterObj || typeof filterObj !== 'object' || Array.isArray(filterObj)) {
    throw new Error('Filter must be a valid object');
  }
  
  const validatedFilter = {};
  
  for (const [field, condition] of Object.entries(filterObj)) {
    if (!ALLOWED_FIELDS.has(field)) {
      throw new Error(`Field not allowed: ${field}`);
    }
    
    const fieldType = FIELD_TYPES[field];
    
    if (condition === null || condition === undefined) {
      validatedFilter[field] = condition;
      continue;
    }
    
    if (typeof condition !== 'object' || Array.isArray(condition)) {
      validatedFilter[field] = validateValue(condition, fieldType);
      continue;
    }
    
    const validatedCondition = {};
    
    for (const [operator, value] of Object.entries(condition)) {
      if (!operator.startsWith('$')) {
        throw new Error(`Invalid operator format: ${operator}`);
      }
      
      if (DANGEROUS_OPERATORS.has(operator)) {
        throw new Error(`Dangerous operator not allowed: ${operator}`);
      }
      
      if (!ALLOWED_OPERATORS.has(operator)) {
        throw new Error(`Operator not allowed: ${operator}`);
      }
      
      validatedCondition[operator] = validateOperatorValue(operator, value, fieldType);
    }
    
    validatedFilter[field] = validatedCondition;
  }
  
  return validatedFilter;
}

function validateAndBuildProjection(projectionObj) {
  if (!projectionObj || typeof projectionObj !== 'object' || Array.isArray(projectionObj)) {
    throw new Error('Projection must be a valid object');
  }
  
  const validatedProjection = {};
  
  for (const [field, value] of Object.entries(projectionObj)) {
    if (!ALLOWED_PROJECTION_FIELDS.has(field)) {
      throw new Error(`Projection field not allowed: ${field}`);
    }
    
    if (value !== 0 && value !== 1 && value !== false && value !== true) {
      throw new Error(`Invalid projection value for ${field}: must be 0, 1, true, or false`);
    }
    
    validatedProjection[field] = value;
  }
  
  return validatedProjection;
}

function validateAndBuildSort(sortObj) {
  if (!sortObj || typeof sortObj !== 'object' || Array.isArray(sortObj)) {
    throw new Error('Sort must be a valid object');
  }
  
  const validatedSort = {};
  
  for (const [field, direction] of Object.entries(sortObj)) {
    if (!ALLOWED_SORT_FIELDS.has(field)) {
      throw new Error(`Sort field not allowed: ${field}`);
    }
    
    if (direction !== 1 && direction !== -1 && direction !== 'asc' && direction !== 'desc') {
      throw new Error(`Invalid sort direction for ${field}: must be 1, -1, 'asc', or 'desc'`);
    }
    
    validatedSort[field] = direction;
  }
  
  return validatedSort;
}

function queryBuilder(filter = {}, projection = {}, sort = {}) {
  try {
    const validatedFilter = validateAndBuildFilter(filter);
    const validatedProjection = validateAndBuildProjection(projection);
    const validatedSort = validateAndBuildSort(sort);
    
    return {
      filter: validatedFilter,
      projection: validatedProjection,
      sort: validatedSort
    };
  } catch (error) {
    throw new Error(`Query validation failed: ${error.message}`);
  }
}

const app = express();
